#include<stdio.h>
#include<stdlib.h>

int main()
{
  int *block_size, *process_size, *flags, *allocation;
  int m, n, i, j, temp, largest, count=0;

  printf("\nEnter the number of memory blocks: ");
  scanf("%d", &m);

