    scanf("%d", &block_size[i]);
  }

  printf("\nEnter the number of processes: ");
  scanf("%d", &n);

  process_size = (int *) malloc(n * sizeof(int));
  flags = (int *) malloc(n * sizeof(int));
  allocation = (int *) malloc(n * sizeof(int));

  for(i=0; i<n; i++)
  {
    printf("\nEnter the size of process %d: ", i+1);
    scanf("%d", &process_size[i]);
  }

  for(i=0; i<n; i++)
  {
    flags[i] = 0;
    allocation[i] = -1;
  }

  for(i=0; i<n; i++)
  {
    largest = -1;
    for(j=0; j<m; j++)
    {
      if(flags[j] == 0 && block_size[j] >= process_size[i])
      {
        if(largest == -1)
        {
          largest = j;
        }
        else if (block_size[j] > block_size[largest])
        {
          largest = j;
        }
      }
    }

    if(largest != -1)
    {
      allocation[i] = largest;
      block_size[largest] -= process_size[i];
      flags[largest] = 1;
    }
  }

  for(i=0; i<n; i++)
  {
    if(allocation[i] != -1)
    {
      printf("\nProcess %d is allocated to Block %d", i+1, allocation[i]+1);
    }
    else
    {
      printf("\nProcess %d is not allocated", i+1);
    }
  }

  return 0;
}
```

In this program, the main change is in the memory allocation loop. We keep track of the largest block that can accommodate the current process size and allocate the process to that block. We then subtract the process size from the block size to reflect the new available space. This way, we allocate the largest available chunk of memory to the process, ensuring that the most amount of memory remains unused.

