//4. Write a c program to simulate paging technique of memory management

#include<stdio.h>
#include<stdlib.h>
#include<math.h>
#include<time.h>

int main()
{
    int n,i,j,frame,page[100],frame_no[100],page_no[100],temp[100],k=0,flag=0,page_fault=0,page_hit=0;
    printf("Enter number of pages: ");
    scanf("%d",&n);
    printf("Enter the pages: ");
    for(i=0;i<n;i++)
        scanf("%d",&page[i]);
    printf("Enter number of frames: ");
    scanf("%d",&frame);
    srand(time(0));
    for(i=0;i<frame;i++)
    {
        frame_no[i]=rand()%10;
    }
    printf("Frame numbers: ");
    for(i=0;i<frame;i++)
        printf("%d ",frame_no[i]);
    printf("\n");
    for(i=0;i<frame;i++)
    {
        page_no[i]=rand()%10;
    }
    printf("Page numbers: ");
    for(i=0;i<frame;i++)
        printf("%d ",page_no[i]);
    printf("\n");
    for(i=0;i<n;i++)
    {
        for(j=0;j<frame;j++)
        {
            if(page[i]==page_no[j])
            {
                flag=1;
                page_hit++;
                break;
            }
        }
        if(flag!=1)
        {
            page_fault++;
            temp[k]=page[i];
            k++;
            if(k>=frame)
                k=0;
        }
        flag=0;
    }
    printf("Page fault: %d\n",page_fault);
    printf("Page hit: %d\n",page_hit);
    return 0;
}
